import React, { useState } from "react";

// Replace these image paths with your actual public folder images
const boardImage = "/torahpoly_board.png";

// Card images - make sure these files are in public/cards/
const cardImages = [
  "/cards/1_bereshitA.png",
  "/cards/1B_bereshitB.png",
  "/cards/har_habayit_1a.png",
  "/cards/har_habayit_1b.png",
  "/cards/tzadik_card.png",
  "/cards/Sotah_47.png",
];

function App() {
  // Dice roll state (1-6)
  const [diceRoll, setDiceRoll] = useState(null);

  // Player position on board (0 to 39, typical Monopoly size)
  const [playerPosition, setPlayerPosition] = useState(0);

  // Card viewer state
  const [currentCardIndex, setCurrentCardIndex] = useState(0);

  // Roll dice handler
  const rollDice = () => {
    const roll = Math.floor(Math.random() * 6) + 1;
    setDiceRoll(roll);

    // Move player position forward by roll steps (loop around board)
    setPlayerPosition((prevPos) => (prevPos + roll) % 40);
  };

  // Card navigation handlers
  const handlePreviousCard = () => {
    setCurrentCardIndex((prev) =>
      (prev - 1 + cardImages.length) % cardImages.length
    );
  };

  const handleNextCard = () => {
    setCurrentCardIndex((prev) => (prev + 1) % cardImages.length);
  };

  return (
    <div style={styles.container}>
      <h1>TorahPoly Board Game</h1>

      {/* Board image */}
      <img
        src={boardImage}
        alt="Game Board"
        style={{ width: "600px", maxWidth: "90vw", border: "2px solid #333" }}
      />

      {/* Player info and dice roll */}
      <div style={{ marginTop: 20 }}>
        <p>
          Player position on board: <strong>{playerPosition}</strong>
        </p>
        <button onClick={rollDice} style={styles.button}>
          Roll Dice
        </button>
        {diceRoll !== null && <p>Dice rolled: {diceRoll}</p>}
      </div>

      {/* Card viewer */}
      <div style={{ marginTop: 40, textAlign: "center" }}>
        <h2>Parsha Card Viewer</h2>
        <img
          src={cardImages[currentCardIndex]}
          alt="Parsha Card"
          style={styles.cardImage}
        />
        <div>
          <button onClick={handlePreviousCard} style={styles.button}>
            Previous
          </button>
          <button
            onClick={handleNextCard}
            style={{ ...styles.button, marginLeft: 10 }}
          >
            Next
          </button>
        </div>
        <p>
          Showing card {currentCardIndex + 1} of {cardImages.length}
        </p>
      </div>
    </div>
  );
}

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    padding: 20,
    textAlign: "center",
    backgroundColor: "#f0f2f5",
    minHeight: "100vh",
  },
  button: {
    backgroundColor: "#007bff",
    border: "none",
    padding: "10px 20px",
    borderRadius: 8,
    color: "white",
    fontSize: 16,
    cursor: "pointer",
  },
  cardImage: {
    width: 300,
    height: "auto",
    borderRadius: 12,
    border: "2px solid #333",
    boxShadow: "0 4px 10px rgba(0,0,0,0.2)",
    marginBottom: 10,
  },
};

export default App;
